// This file is part of the uutils coreutils package.
//
// Regression test: writing to a closed pipe should not print an EPIPE message.

use std::process::{Command, Stdio};

use uutests::util::TestScenario;
use uutests::util_name;

#[test]
#[cfg(unix)]
fn test_cat_does_not_print_broken_pipe_when_downstream_closes() {
    // Run `cat /dev/zero | head -c 1 >/dev/null`.
    // head will exit after reading 1 byte; cat should not print an EPIPE message.
    let scene = TestScenario::new(util_name!());
    let coreutils_bin = scene.bin_path.clone();

    let output = Command::new(&coreutils_bin)
        .arg("cat")
        .arg("/dev/zero")
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .and_then(|mut cat_child| {
            let cat_stdout = cat_child.stdout.take().unwrap();

            let head_output = Command::new("head")
                .args(["-c", "1"])
                .stdin(Stdio::from(cat_stdout))
                .stdout(Stdio::null())
                .stderr(Stdio::piped())
                .output()?;

            // Ensure head succeeded; then wait for cat.
            assert!(head_output.status.success());
            let cat_output = cat_child.wait_with_output()?;
            Ok::<_, std::io::Error>(cat_output)
        })
        .expect("failed to run pipeline");

    // cat may exit with success or SIGPIPE-derived code depending on platform,
    // but it must not print a broken pipe error.
    let stderr = String::from_utf8_lossy(&output.stderr);
    assert!(!stderr.contains("Broken pipe"), "stderr was: {stderr}");
    assert!(!stderr.contains("EPIPE"), "stderr was: {stderr}");
}

